const fs = require('fs');
const { chromium } = require('playwright');

(async () => {
  const csv = fs.readFileSync('bookmarks.csv', 'utf-8')
    .split('\n')
    .map(l => l.trim())
    .filter(l => l);

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();

  for (const line of csv) {
    const [no, url] = line.split(',');
    const tweetId = url.match(/status\/(\d+)/)[1];

    const page = await context.newPage({
      viewport: { width: 440 + 2, height: 1200 }
    });

    console.log(`${no}: ${url}`);
    await page.goto(`https://platform.twitter.com/embed/Tweet.html?dnt=true&%3D%3D&frame=false&hideCard=false&hideThread=true&id=${tweetId}&lang=en&theme=dark&widgetsVersion=2b959255e8896%3A1673658205745`);

    // ページ読込待ち
    const tweet = await page.locator('article').first();
    await tweet.waitFor({ timeout: 10000 });

    // ページ描画待ち(3-6s)
    await page.waitForTimeout(3000 + Math.random() * 3000);

    // スクリーンショット保存
    await tweet.screenshot({ path: `tweet_${no}.png` });

    await page.close();
  }

  await browser.close();
})();
